    id: "jubilee",
    title: "Jubilee",
    year: 1935,
    era: "early",
    type: "musical",
    openingDate: "1935-10-12",
    theatre: "Imperial Theatre",
    composer: "Cole Porter",
    lyricist: "Cole Porter",
