    id: "on-the-town",
    title: "On the Town",
    year: 1944,
    era: "golden-age",
    type: "musical",
    openingDate: "1944-12-28",
    theatre: "Adelphi Theatre",
    composer: "Leonard Bernstein",
    lyricist: "Betty Comden & Adolph Green",
    bookWriter: "Betty Comden & Adolph Green Producers: Oliver Smith & Paul Feigay",
    director: "George Abbott",
    choreographer: "Jerome Robbins",
