    id: "three-wishes-for-jamie-a-new-musical-play",
    title: "Three Wishes for Jamie “A New Musical Play”",
    year: 1952,
    era: "golden-age",
    type: "musical",
    openingDate: "1952-03-21",
    closingDate: "1952-06-07",
    theatre: "Mark Hellinger Theatre (during run, the musical transferred to the Plymouth Theatre)",
