    id: "anna-russell-and-her-little-show-an-intimate-revue",
    title: "Anna Russell and Her Little Show “An Intimate Revue”",
    year: 1953,
    era: "golden-age",
    type: "musical",
    openingDate: "1953-09-07",
    closingDate: "1953-09-19",
    theatre: "Vanderbilt Theatre",
