    title: "Take Me Along",
    year: 1959,
    era: "golden-age",
    type: "musical",
    openingDate: "1959-10-22",
    closingDate: "1960-12-17",
    theatre: "Shubert Theatre",
    composer: "Bob Merrill",
    lyricist: "Bob Merrill",
    bookWriter: "Joseph Stein & Robert Russell",
    director: "Peter Glenville",
    choreographer: "Onna White",
