    notableCast: ["Samuel E. Wright","Heather Headley","John Vickery","Tsidii Le Loka","Geoff Hoyle","Tom Alan Robbins","Gina Breedlove","Jason Raize","Stanley Wayne Mathis","Tracy Nicole Chapman","Kevin Cahoon","Scott Irby-Ranniar","Kajuana Shuford","Max Casella"],
    songs: ["Circle of Life","t Wait to Be King\", ",", ",", ","The Morning Report","I Just Can’t Wait to Be King","Chow Down","They Live in You","Be Prepared","Hakuna Matata","One By One","The Madness of King Scar","Shadowland","Endless Night","Can’t You Feel the Love Tonight","He Lives in You","King of Pride Rock"],
