    notableCast: ["Sutton Foster","Harriet Sansom Harris","Marc Kudisch","Gavin Creel","Sheryl Lee Ralph","Harriet Harris","Angela Christian","Ken Leung","Francis Jue","Anne L. Nathan"],
    songs: ["Not for the Life of Me","Gimme Gimme","What Do I Need with Love","Forget About the Boy","Only in New York","I’m Falling in Love with Someone","Long as I’m Here with You"],
    tonyWins: 6,
